import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import Navbar from '../components/Navbar';
import api from '../services/api';

function NewApplication() {
  const navigate = useNavigate();
  const [loading, setLoading] = useState(false);
  const [uploadMode, setUploadMode] = useState(true);
  const [files, setFiles] = useState({
    financials: null,
    gst: null,
    bankStatement: null,
    mca: null
  });
  const [formData, setFormData] = useState({
    companyName: '',
    sector: 'Manufacturing',
    incorporationYear: 2015,
    promoters: '',
    revenue: 100,
    ebitda: 15,
    netProfit: 8,
    totalDebt: 40,
    netWorth: 60,
    gstTurnover: 95,
    capacityUtilization: 75,
    managementQuality: 7,
    siteVisitScore: 7
  });

  const handleChange = (e) => {
    setFormData({
      ...formData,
      [e.target.name]: e.target.value
    });
  };

  const handleFileChange = (e) => {
    setFiles({
      ...files,
      [e.target.name]: e.target.files[0]
    });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);

    try {
      let response;
      if (uploadMode) {
        // File upload mode
        const formDataObj = new FormData();
        formDataObj.append('companyName', formData.companyName);
        formDataObj.append('sector', formData.sector);
        formDataObj.append('incorporationYear', formData.incorporationYear);
        formDataObj.append('promoters', formData.promoters);

        if (files.financials) formDataObj.append('financials', files.financials);
        if (files.gst) formDataObj.append('gst', files.gst);
        if (files.bankStatement) formDataObj.append('bankStatement', files.bankStatement);
        if (files.mca) formDataObj.append('mca', files.mca);

        response = await api.processApplicationWithFiles(formDataObj);
      } else {
        // Manual entry mode
        response = await api.processApplication(formData);
      }

      localStorage.setItem('results', JSON.stringify(response));
      navigate('/results');
    } catch (error) {
      alert('Error processing application: ' + error.message);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="gradient-bg" style={{ minHeight: '100vh' }}>
      <Navbar />

      <div className="container">
        <div className="card" style={{ maxWidth: '900px', margin: '2rem auto' }}>
          <h1 className="title" style={{ fontSize: '2.5rem' }}>
            📋 New Credit Application
          </h1>
          <p style={{ textAlign: 'center', color: '#666', marginBottom: '1rem' }}>
            Upload documents or enter details manually for instant credit analysis
          </p>

          {/* Toggle Mode */}
          <div style={{ textAlign: 'center', marginBottom: '2rem' }}>
            <button
              type="button"
              className={uploadMode ? 'btn' : 'btn-secondary'}
              onClick={() => setUploadMode(true)}
              style={{ marginRight: '1rem' }}
            >
              📁 Upload Documents
            </button>
            <button
              type="button"
              className={!uploadMode ? 'btn' : 'btn-secondary'}
              onClick={() => setUploadMode(false)}
            >
              ✍️ Manual Entry
            </button>
          </div>

          <form onSubmit={handleSubmit}>
            {/* Company Information */}
            <h3 style={{ color: '#667eea', marginBottom: '1rem' }}>Company Information</h3>
            <div className="grid grid-2">
              <div>
                <label className="label">Company Name *</label>
                <input
                  type="text"
                  name="companyName"
                  className="input"
                  value={formData.companyName}
                  onChange={handleChange}
                  required
                />
              </div>
              <div>
                <label className="label">Sector *</label>
                <select
                  name="sector"
                  className="input"
                  value={formData.sector}
                  onChange={handleChange}
                >
                  <option>Manufacturing</option>
                  <option>Services</option>
                  <option>Trading</option>
                  <option>NBFC</option>
                  <option>IT/Software</option>
                </select>
              </div>
              <div>
                <label className="label">Incorporation Year</label>
                <input
                  type="number"
                  name="incorporationYear"
                  className="input"
                  value={formData.incorporationYear}
                  onChange={handleChange}
                />
              </div>
              <div>
                <label className="label">Promoters (comma separated)</label>
                <input
                  type="text"
                  name="promoters"
                  className="input"
                  placeholder="John Doe, Jane Smith"
                  value={formData.promoters}
                  onChange={handleChange}
                />
              </div>
            </div>

            {uploadMode ? (
              /* File Upload Mode */
              <>
                <h3 style={{ color: '#667eea', margin: '2rem 0 1rem' }}>📄 Upload Documents</h3>
                <div className="grid grid-2">
                  <div className="file-upload">
                    <label className="label">📊 Financial Statements (PDF/Excel)</label>
                    <input
                      type="file"
                      name="financials"
                      className="input"
                      accept=".pdf,.xlsx,.xls"
                      onChange={handleFileChange}
                    />
                    {files.financials && <span className="file-name">✓ {files.financials.name}</span>}
                  </div>
                  <div className="file-upload">
                    <label className="label">🧾 GST Returns (JSON/PDF)</label>
                    <input
                      type="file"
                      name="gst"
                      className="input"
                      accept=".json,.pdf"
                      onChange={handleFileChange}
                    />
                    {files.gst && <span className="file-name">✓ {files.gst.name}</span>}
                  </div>
                  <div className="file-upload">
                    <label className="label">🏦 Bank Statement (CSV/PDF)</label>
                    <input
                      type="file"
                      name="bankStatement"
                      className="input"
                      accept=".csv,.pdf"
                      onChange={handleFileChange}
                    />
                    {files.bankStatement && <span className="file-name">✓ {files.bankStatement.name}</span>}
                  </div>
                  <div className="file-upload">
                    <label className="label">📋 MCA Filings (JSON/PDF)</label>
                    <input
                      type="file"
                      name="mca"
                      className="input"
                      accept=".json,.pdf"
                      onChange={handleFileChange}
                    />
                    {files.mca && <span className="file-name">✓ {files.mca.name}</span>}
                  </div>
                </div>
              </>
            ) : (
              /* Manual Entry Mode */
              <>
                <h3 style={{ color: '#667eea', margin: '2rem 0 1rem' }}>Financial Data (₹ Crores)</h3>
                <div className="grid grid-3">
                  <div>
                    <label className="label">Revenue</label>
                    <input
                      type="number"
                      name="revenue"
                      className="input"
                      value={formData.revenue}
                      onChange={handleChange}
                    />
                  </div>
                  <div>
                    <label className="label">EBITDA</label>
                    <input
                      type="number"
                      name="ebitda"
                      className="input"
                      value={formData.ebitda}
                      onChange={handleChange}
                    />
                  </div>
                  <div>
                    <label className="label">Net Profit</label>
                    <input
                      type="number"
                      name="netProfit"
                      className="input"
                      value={formData.netProfit}
                      onChange={handleChange}
                    />
                  </div>
                  <div>
                    <label className="label">Total Debt</label>
                    <input
                      type="number"
                      name="totalDebt"
                      className="input"
                      value={formData.totalDebt}
                      onChange={handleChange}
                    />
                  </div>
                  <div>
                    <label className="label">Net Worth</label>
                    <input
                      type="number"
                      name="netWorth"
                      className="input"
                      value={formData.netWorth}
                      onChange={handleChange}
                    />
                  </div>
                  <div>
                    <label className="label">GST Turnover</label>
                    <input
                      type="number"
                      name="gstTurnover"
                      className="input"
                      value={formData.gstTurnover}
                      onChange={handleChange}
                    />
                  </div>
                </div>
              </>
            )}



            {/* Primary Insights */}
            <h3 style={{ color: '#667eea', margin: '2rem 0 1rem' }}>Primary Insights</h3>
            <div className="grid grid-3">
              <div>
                <label className="label">Capacity Utilization (%)</label>
                <input
                  type="range"
                  name="capacityUtilization"
                  min="0"
                  max="100"
                  value={formData.capacityUtilization}
                  onChange={handleChange}
                  style={{ width: '100%' }}
                />
                <div style={{ textAlign: 'center', fontWeight: '600' }}>
                  {formData.capacityUtilization}%
                </div>
              </div>
              <div>
                <label className="label">Management Quality (1-10)</label>
                <input
                  type="range"
                  name="managementQuality"
                  min="1"
                  max="10"
                  value={formData.managementQuality}
                  onChange={handleChange}
                  style={{ width: '100%' }}
                />
                <div style={{ textAlign: 'center', fontWeight: '600' }}>
                  {formData.managementQuality}/10
                </div>
              </div>
              <div>
                <label className="label">Site Visit Score (1-10)</label>
                <input
                  type="range"
                  name="siteVisitScore"
                  min="1"
                  max="10"
                  value={formData.siteVisitScore}
                  onChange={handleChange}
                  style={{ width: '100%' }}
                />
                <div style={{ textAlign: 'center', fontWeight: '600' }}>
                  {formData.siteVisitScore}/10
                </div>
              </div>
            </div>

            {/* Submit Button */}
            <div style={{ textAlign: 'center', marginTop: '3rem' }}>
              {loading ? (
                <div className="spinner"></div>
              ) : (
                <button type="submit" className="btn">
                  🚀 Process Application
                </button>
              )}
            </div>
          </form>
        </div>
      </div>
    </div>
  );
}

export default NewApplication;
